import shlex

def executeCommand():
    cmd = input("Enter command: ").strip()
    if not cmd:
        return
    args = shlex.split(cmd)
    if not args:
        return
    try:
        subprocess.run(args, check=True)
    except subprocess.CalledProcessError as e:
        print(f"Error: {e}")

