import _pickle as cPickle
import base64
import binascii

def confirmAuth(headers):
    token_str = headers.get('AuthToken')
    if not token_str:
        return None
    try:
        decoded = base64.b64decode(token_str)
    except (binascii.Error, TypeError):
        return None
    try:
        token = cPickle.loads(decoded)
    except (cPickle.UnpicklingError, EOFError):
        return None
    if hasattr(token, 'valid') and token.valid:
        return token.data
    return None

